	$old_data = getRecord('utedb', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: utedb_before_update
	if(function_exists('utedb_before_update')) {
		$args = ['old_data' => $old_data];
		if(!utedb_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'utedb',
		backtick_keys_once($set),
		['`utedb_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="utedb_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('utedb', $data['selectedID'], calculated_fields()['utedb']);

	// hook: utedb_after_update
	if(function_exists('utedb_after_update')) {
		if($row = getRecord('utedb', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['utedb_id'];
		$args = ['old_data' => $old_data];
		if(!utedb_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('utedb', $selected_id);
}

